mapper.update:
update spboard set
filename=#{filename},
title=#{title}, content=#{content}, ip=#{ip}, modify_date=sysdate where board_num=#{board_num}

mapper.insert:
insert into spboard_reply(
re_num, re_content, re_ip, board_num, mem_num
) values (
spreply_seq.nextval, #{re_content}, #{re_ip}, #{board_num}, #{mem_num}
)

mapper.select:
select * from spboard_reply join spmember using (mem_num) left outer join (select re_num, count(*) resp_cnt from spboard_response group by re_num) using (re_num) where board_num=#{board_num}
order by re_num desc
offset #{skip} rows fetch next #{limit} rows only

mapper.delete:
delete from spboard_response where te_num in (
select te_num from spboard_response
start with te_num = #{te_num}
connect by prior te_num = te_parent_num
)
